import api from "./api";
import { getUserFromLocalStorage } from "./authService";

// Lấy tất cả sự kiện, cho phép truyền vào tham số cho Admin/User
export const getAllEvents = async (isAdmin = false) => {
  const endpoint = isAdmin ? "/admin/events" : "/events"; // Dựa vào tham số isAdmin để gọi đúng API
  return await api.get(endpoint);
};

// Lấy sự kiện theo ID
export const getEventById = (id) => api.get(`/events/${id}`, {
  headers: getUserFromLocalStorage()
});

// Lấy chi tiết sự kiện kèm vé
export const getEventDetailWithTickets = (id) =>
  api.get(`/events/${id}/details`, {
    headers: getUserFromLocalStorage()
  });

// Quản trị viên tạo sự kiện
export const adminCreateEvent = (data) =>
  api.post("/events", data, {
    headers: getUserFromLocalStorage()
  });

// Quản trị viên cập nhật sự kiện
export const adminUpdateEvent = (id, data) =>
  api.put(`/events/${id}`, data, {
    headers: getUserFromLocalStorage()
  });

// Quản trị viên xóa sự kiện
export const adminDeleteEvent = (id) =>
  api.delete(`/events/${id}`, {
    headers: getUserFromLocalStorage()
  });
